profile-card.example:
const { div, span, h3 } = tags;
Card({},
  Card.Body({ class: css('_flex _col _aic _gap3') },
    Avatar({ src: player.avatar, size: 'xl', class: css('gg-glow') }),
    h3({ class: css('d-gradient-text _heading3') }, player.name),
    Badge({ variant: 'primary' }, player.rank),
    div({ class: css('_wfull') },
      div({ class: css('_flex _jcsb _mb1') },
        span({ class: css('gg-label _textxs') }, 'XP'),
        span({ class: css('gg-data _textxs') }, `${player.xp} / ${player.nextLevel}`)
      ),
      div({ class: css('gg-xp-bar'), style: `--gg-xp:${player.xpPercent}%` })
    )
  )
)

