auth-modal.example:
Modal({
  visible: showAuth,
  onClose: () => setShowAuth(false),
  class: css('gg-mesh')
},
  div({ class: css('_flex _col _aic _gap4 _p6') },
    span({ class: css('d-gradient-text _heading3') }, 'JOIN THE GUILD'),
    Input({ label: 'Gamertag', placeholder: 'Enter your gamertag' }),
    Input({ label: 'Access Code', type: 'password' }),
    Button({ variant: 'primary', class: css('_wfull gg-glow') }, 'SIGN IN')
  )
)

